```python
ssl_spec = {
            'type': 'dict',
            'items': {
                'enabled': {
                    'type': 'bool',
                    'default': False,
                    'description': 'Serve content using SSL',
                    'fallback': 'ssl.enabled',
                },
                'private_key': {
                    'type': 'str',
                    'description': 'Path to a private key',
                    'fallback': 'ssl.private_key',
                },
                'public_key': {
                    'type': 'str',
                    'description': 'Path to a public key',
                    'fallback': 'ssl.public_key',
                },
            },
}
```

