import { mutate, outputFromMessage } from "@nteract/records";

let outputs = [];
const appendOutput = produce(mutate.appendOutput);

channels.subscribe(msg => {
  const output = outputFromMessage(msg);
  outputs = appendOutput(outputs, output)
}

